#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int XE, YE, N;
        char DIRE;
        scanf("%d %d %c", &XE, &YE, &DIRE);
        scanf("%d", &N);
        double minTime = 1e9;
        for (int i = 0; i < N; i++) {
            int XA, YA;
            char DIRA;
            scanf("%d %d %c", &XA, &YA, &DIRA);
            double time = 0;
            if (DIRE == 'U' && DIRA == 'D') {
                time = (YA - YE) / 2.0;
            } else if (DIRE == 'D' && DIRA == 'U') {
                time = (YE - YA) / 2.0;
            } else if (DIRE == 'R' && DIRA == 'L') {
                time = (XA - XE) / 2.0;
            } else if (DIRE == 'L' && DIRA == 'R') {
                time = (XE - XA) / 2.0;
            }
            if (time > 0 && time < minTime) {
                minTime = time;
            }
        }
        if (minTime == 1e9) {
            printf("SAFE\n");
        } else {
            printf("%.1f\n", minTime);
        }
    }
    return 0;
}

