const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [XE, YE, DIRE] = readline().split(' ');
    const N = parseInt(readline());
    let minTime = 1e9;
    for (let j = 0; j < N; j++) {
        const [XA, YA, DIRA] = readline().split(' ');
        let time = 0;
        if (DIRE === 'U' && DIRA === 'D') {
            time = (parseInt(YA) - parseInt(YE)) / 2;
        } else if (DIRE === 'D' && DIRA === 'U') {
            time = (parseInt(YE) - parseInt(YA)) / 2;
        } else if (DIRE === 'R' && DIRA === 'L') {
            time = (parseInt(XA) - parseInt(XE)) / 2;
        } else if (DIRE === 'L' && DIRA === 'R') {
            time = (parseInt(XE) - parseInt(XA)) / 2;
        }
        if (time > 0 && time < minTime) {
            minTime = time;
        }
    }
    if (minTime === 1e9) {
        console.log('SAFE');
    } else {
        console.log(minTime.toFixed(1));
    }
}
